                }
            }
            dp = move(new_dp);
        }
        return dp.back();
    }

private:
    template<typename T>
    struct LazyHeap {
        LazyHeap() {

        }

        void push(int val) {
            heap.emplace(val);
        }

        void full_remove() {
            priority_queue<int, vector<int>, T> new_heap;
            while (!heap.empty()) {
                const auto x = heap.top(); heap.pop();
                if (!to_remove.empty() && x == to_remove.top()) {
                    to_remove.pop();
                } else {
                    new_heap.emplace(x);
                }
            }
            heap = move(new_heap);
        }

        void remove(int val) {
            to_remove.emplace(val);
            if (to_remove.size() > heap.size() - to_remove.size()) {
                full_remove();
            }
        }

        void pop() {
            remove(top());
        }

        int top() {
            while (!heap.empty() && !to_remove.empty() && heap.top() == to_remove.top()) {
                heap.pop();
                to_remove.pop();
            }
            return heap.top();
        }

        int64_t size() {
            return heap.size() - to_remove.size();
        }

        bool empty() {
            return size() == 0;
        }

        priority_queue<int, vector<int>, T> heap, to_remove;
    };

    struct Slidingsw {
        Slidingsw() {

        }

        void add(int val) {
            if (left.empty() || val <= left.top()) {
                left.push(val);
                total1 += val;
            } else {
                right.push(val);
                total2 += val;
            }
            rebalance();
        }

        void remove(int val) {
            if (val <= left.top()) {
                left.remove(val);
                total1 -= val;
            } else {
                right.remove(val);
                total2 -= val;
            }
            rebalance();
        }

        void rebalance() {
            if (left.size() < right.size()) {
                total2 -= right.top();
                total1 += right.top();
                left.push(right.top());
                right.pop();
            } else if (left.size() > right.size() + 1) {
                total1 -= left.top();
                total2 += left.top();
                right.push(left.top());
                left.pop();
            }
        }

        int median() {
            return left.top();
        }

        LazyHeap<less<int>> left;
        LazyHeap<greater<int>> right;
        int64_t total1 = 0;
        int64_t total2 = 0;
    };
};

